var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"앗, 토리야! 책은 뜯어먹으면 안돼! 착하지!","JPN":"あっ、トリったら！　本を破っちゃ\\nダメでしょ！　いい子にしてないと。","ENG":"Ah, Hopper! Don't chew on the books! Be a good boy!","TWN":"啊，托里！書不是用來吃的！乖喔。"},"stage":{"bg":"DORMITORY_2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"흐그그...... 고미 대원의 침에 인형들이 흠뻑 젖어버렸다...... 한정판이었는데......","JPN":"ううぅ……クマたん隊員のよだれで、\\nぬいぐるみたちがびちょ濡れに……限定版だったのに……","ENG":"Ugh... All of the stuffed animals are soaked in Operative Teddy's saliva... They were limited editions...","TWN":"唔唔唔……娃娃都沾滿了咕美熊熊的口水……這是限定版耶……"},"stage":{"bg":"DORMITORY_2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L5_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"음...... 동물구조도 좋지만. 이래서야 우리 힘만으로 돌보는 데는 한계가 있겠는데?","JPN":"うーん……動物の救助もいいけど、私たちの力だけじゃ面倒を見るのに限界があると思わない？","ENG":"Hmm... It's nice that we're saving the animals. But I don't think we'll be able to take care of them on our own.","TWN":"嗯……雖然幫助動物是很好，但這樣只靠我們來照顧，是有極限的吧？"},"stage":{"bg":"DORMITORY_2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"사료값으로 쓰는 동아리 활동비도 간당간당하고......","JPN":"餌代に使ってるサークル活動費もギリギリだし……","ENG":"We're also running low on the club activity funds from buying pet food...","TWN":"用在飼料錢的社團活動費也快不夠了……"},"stage":{"bg":"DORMITORY_2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"역시...... 보호소에 맡기는 편이 나은 걸까요?","JPN":"やっぱり……保護施設に預けた方がいいですか？","ENG":"I suppose... we should take them to the shelter?","TWN":"果然……交給收容所會比較好嗎？"},"stage":{"bg":"DORMITORY_2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"어쩌면 그럴 수도 있지.","JPN":"そうなる可能性もあるよね。","ENG":"That's probably for the best.","TWN":"也許是吧。"},"stage":{"bg":"DORMITORY_2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L11_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"하지만...... 이 아이들이 버림 받았다고 생각하게 만들고 싶지는 않은걸요......","JPN":"でも……この子たちに捨てられたと思って欲しくはないんです……","ENG":"But... I don't want them to feel like we abandoned them...","TWN":"但是……我不希望這些孩子覺得自己被拋棄了……"},"stage":{"bg":"DORMITORY_2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L12_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"집착이고, 오지랖처럼 보일 수도 있겠지만......","JPN":"執着やお節介なのかもしれませんが……","ENG":"It may sound obsessive and meddling...","TWN":"雖然你們會覺得這樣很固執、多管閒事……"},"stage":{"bg":"DORMITORY_2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L13_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"새로운 주인을 찾을 때까진 어떻게든 책임을 져 주고 싶어요!","JPN":"新しい飼い主が見つかるまで、\\nちゃんと責任を果たしたいんです！","ENG":"But I want to be responsible for them until we find them a new owner!","TWN":"在幫牠們找到新主人之前，我想要負起責任，想辦法照顧牠們！"},"stage":{"bg":"DORMITORY_2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L14_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"으음......","JPN":"うーん……","ENG":"Mm...","TWN":"嗯……"},"stage":{"bg":"DORMITORY_2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"괜찮아! 너무 걱정하지 마.","JPN":"大丈夫！　あまり心配しないで。","ENG":"It's okay! You don't have to worry too much.","TWN":"不要緊！不用太擔心。"},"stage":{"bg":"DORMITORY_2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L16_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"이건 내 경험인데, 뭔가 문제가 생기면 반드시 해결책이 따라오는 법이거든!","JPN":"今までの経験上、何か問題が起きると必ず解決策も同時に見つかるから！","ENG":"Based on my experience, whenever a problem arises, the solution comes along with it!","TWN":"雖然是我個人的經驗，但有什麼問題發生的時候，解決方法都會隨之而來的！"},"stage":{"bg":"DORMITORY_2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"그, 그런가요?","JPN":"そ、そうなんですか？","ENG":"R-really?","TWN":"是、是這樣嗎？"},"stage":{"bg":"DORMITORY_2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"역시 호진 언니 대원은 대단하다. 연장자로서의 관록이 느껴진다.","JPN":"さすが、マユミ隊員は素晴らしい。年長者としての貫禄を感じる。","ENG":"We can always count on you, Operative Hojin. You carry the weight as the senior member.","TWN":"不愧是鎬眞姐姐隊員，太厲害了，我感受到了身為前輩的威嚴。"},"stage":{"bg":"DORMITORY_2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"그래서 해결책이 뭔지 알려 달라.","JPN":"それで、解決策は？","ENG":"So tell us what the solution is.","TWN":"那快告訴我們解決方法是什麼吧。"},"stage":{"bg":"DORMITORY_2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"으음...... 그러니까 일단은......","JPN":"うーん……ひとまず……","ENG":"Mm... First, let's start with...","TWN":"嗯……所以我們就先……"},"stage":{"bg":"DORMITORY_2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"그래! 편지를 쓰자!","JPN":"手紙を書こう！","ENG":"Yeah! Let's write a letter!","TWN":"對了，來寫信吧！"},"stage":{"bg":"DORMITORY_2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"편지요?","JPN":"手紙ですか？","ENG":"A letter?","TWN":"信？"},"stage":{"bg":"DORMITORY_2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"그래! 이럴 땐 후원이 필요한 법이거든!","JPN":"そう！　こういう時は支援が必要でしょ？","ENG":"Yup! In times like this, we need a sponsor!","TWN":"沒錯！這種時候就是需要後援啊！"},"stage":{"bg":"DORMITORY_2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"편지가 하나 왔습니다.","JPN":"手紙が届きました。","ENG":"Something came in the mail.","TWN":"來了一封信。"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"편지? 전자 메일을 말하는 건가?","JPN":"手紙？　メールのことを言っているのか？","ENG":"Mail? You mean e-mail?","TWN":"信？你是說電子郵件嗎？"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"아니요. 손으로 쓴 편지입니다.","JPN":"いえ、手書きの手紙です。","ENG":"No. A hand-written letter.","TWN":"不是，是用手寫的信。"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"손으로? 요즘 시대에도 그런 걸 쓰는 사람이 남아있었군.","JPN":"手書き？　今の時代こんなものを書く人間が残っていたとは。","ENG":"Hand-written? I had no idea that people still write letters in the modern age.","TWN":"手寫的？這個時代還有親筆寫信的人啊。"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"전자 메일이 간편하긴 하지만, 아무래도 본인은 정성을 어필하고 싶었던 모양입니다.","JPN":"メールの方が楽ですが、心を込めて伝えたかったようですね。","ENG":"E-mails are more convenient, but I believe the sender wanted to appeal their sincerity.","TWN":"雖然電子郵件比較方便，但看來寄信的人想要表現他們的誠意呢。"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"말려 붙인 야생화와 동물스티커로 편지지를 정성스럽게 꾸며놨더군요.","JPN":"野花のドライフラワーに動物のシールで、手紙のデコレーションにも力を入れたようです。","ENG":"The letter was carefully decorated with dried flowers and animal stickers.","TWN":"他們用乾燥花和小動物貼紙，把信封裝飾得漂漂亮亮的。"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"오, 흥미로운걸? 그런 건 읽어볼 수밖에 없겠군.","JPN":"おぉ、それは興味深い。中身を見てみよう。","ENG":"Oh, that's interesting. I can't ignore it when they put in so much effort.","TWN":"哦，很有趣嘛？看來我非讀不可了呢。"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"확인해보니 관리국 아카데미 중등부에 재학 중인 양하림이란 학생이 보낸 편지였습니다.","JPN":"確認したところ、管理局カウンターアカデミー中等部に在学中のホシノ・ウサギという学生からの手紙です。","ENG":"It was sent by a student named Yang Harim from the Administration Junior High Academy.","TWN":"經過我確認後……這是就讀管理局學院國中部，一個叫作楊夏琳的學生寫的信。"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"요지는 동아리활동에 필요한 금전적 지원을 부탁하는 내용이더군요.","JPN":"要約しますと、サークル活動に必要な金銭的支援を\\n要求する内容になっています。","ENG":"In short, she wants financial sponsorship for running their activity club.","TWN":"主要內容是希望我們能提供他們社團活動所需要的經費支援。"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"아마도 행운의 편지처럼 여기저기에 써서 보낸 것 같습니다.","JPN":"おそらく幸運の手紙のように、色んなところに書いて送っているようです。","ENG":"It also seemed like she sent them out like a chain letter to everyone.","TWN":"應該就像幸運信，寫給了很多地方的樣子。"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"동아리라...... 참 그리운 이름인걸.","JPN":"サークルか……懐かしい響きだ。","ENG":"A club... That brings back some memory.","TWN":"社團啊……真令人懷念的名稱啊。"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"그런데 대체 어떤 활동을 하길래 여기까지 지원을 요청한 거지?","JPN":"だが、金銭的支援が必要なサークルとは、どういうことをしているのだ？","ENG":"But what kind of club activity requires a sponsorship?","TWN":"話說，他們到底是什麼樣的社團活動，把信都寄到這裡來了。"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"화이트래빗은 동물을 구조하고 보살피는 것이 목적인 학내 동아리입니다.","JPN":"ホワイトラビットは動物を救助し、世話をすることを\\n目的とした学内サークルです。","ENG":"White Rabbit is a school club that serves to save and care for animals in need of help.","TWN":"白兔社是以救助並保護動物為目的的校內組織。"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"이런 선의의 활동은 카운터에 대한 대중의 인식개선에 큰 도움이 되죠.","JPN":"このような素晴らしい活動は、カウンターに対する\\n世間の認識改善に大いに役立ちます。","ENG":"These sort of benevolent actions are helpful in increasing the public's awareness of Counters.","TWN":"這種慈善活動，可以大大改善大眾對制裁者的印象。"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"하지만 최근에 보호하는 동물이 너무 많아져서 교내 지원금만으로는 유지가 어려운 상황인 것 같더군요.","JPN":"しかし最近保護している動物が増え、現在の学内支援金だけでは\\n維持が難しいようですね。","ENG":"But they've been overwhelmed with the number of animals in care. So they're having trouble maintaining with just the school's funding.","TWN":"但最近需要保護的動物急劇增加，只靠校內的支援金，他們很難維持現狀。"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"기특한 얘기로군, 하지만 우리와는 별로 어울리지 않는 일인 것 같은데.","JPN":"感心な話だな。しかし、我々には不釣り合いな活動ではないか？","ENG":"That's very admirable. But I'm not sure if it fits well with our company.","TWN":"真是個溫馨的故事。但這種事情好像和我們不太相配吧。"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"항상 부족한 예산 때문에 고통 받고 있는 자네라면 당연히 단칼에 거절했겠지?","JPN":"予算不足で首が回らないのはよく知っているだろうし、もちろん断りの連絡をいれるのだろう？","ENG":"I'm sure you declined immediately, since we're always suffering due to our lack of funding.","TWN":"總是因為預算不足而飽受痛苦的你，當然是一口拒絕吧。"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"그럴리가요. 이런 훌륭한 활동을 하는 어린이들을 모른 척할 순 없죠.","JPN":"いえ、このような素晴らしい活動をする子どもたちの頼みを無視するわけにはいきません。","ENG":"Of course not. I wouldn't ignore these children when they're doing incredible work.","TWN":"怎麼會呢，我無法對這些做公益的小朋友們視而不見啊。"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"보고가 끝나는 대로 지원 수락 답장을 보낼 예정입니다.","JPN":"報告が済み次第、支援承諾の返事を出すつもりです。","ENG":"I'm going to accept their request as soon as this report is done.","TWN":"等報告一結束，我就打算寫封答應支援的回信。"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"누구냐, 네놈은?","JPN":"貴様は何者だ？","ENG":"Who are you?","TWN":"你是什麼人？"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"이수연 부사장이 아니라는 건 확실하군. 어떻게 여기까지 침입한 거지?","JPN":"カナミ・キズナ副社長でないというのは確かだな。どうやってここに侵入した？","ENG":"I can tell that you're definitely not Lee Sooyeon. How did you get in here?","TWN":"你一定不是李秀妍副總，你是怎麼侵入這裡的？"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L49_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"눈 찔러 버리기 전에 그만 노려 보세요.","JPN":"そう睨まないでください。目を潰しますよ。","ENG":"Stop staring at me before I poke your eyes out.","TWN":"不准這樣瞪我，小心我戳穿你的眼睛。"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"......크흠! 크흠!!","JPN":"……ゴ、ゴホン！","ENG":"Ahem! Ahem!!","TWN":"……咳咳！咳咳！！"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"뭐, 저도 자선사업 따위에 관심 있는 건 아닙니다.","JPN":"私も慈善事業に興味があるわけではありません。","ENG":"Well, I'd have to admit that I'm not interested in charity work.","TWN":"我對慈善事業不感興趣。"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"하지만 이 아이들이 보낸 편지에 자기들을 도와주기만 한다면 현장학습 명목으로 태스크포스 작전에 참가하겠다고 써 있었거든요.","JPN":"しかしこの子たちの手紙に、支援をしてくれたら現場学習という名目で\\nタスクフォースの作戦に参加すると書いてあったのです。","ENG":"But the children who sent this letter promised to join TASKFORCE missions as part of their field trip if we help them out.","TWN":"但在這些小朋友寫的信裡，提到只要我們願意幫助他們，他們就會以現場學習的名義，參加特遣勢力的作戰。"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"당연히 무상으로 말이죠.","JPN":"もちろん無償でです。","ENG":"For free, of course.","TWN":"這當然是無償的。"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"아, 역시 자네가 맞군. 오해해서 미안하네.","JPN":"やはり、そういうことか。それでこそ君だ。","ENG":"Ah, it is you. I'm sorry about the misunderstanding.","TWN":"啊，真的是你。我剛剛誤會你了，真抱歉。"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"......평소에 절 대체 어떻게 생각하고 계셨던 건지 궁금하군요.","JPN":"……一体私をどういう人間だと思っているのですか？","ENG":"I'm curious to know what you usually think of me.","TWN":"……我很好奇，您平時到底把我想成什麼了。"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"어쨌든 관리국 아카데미에서 뽑아갈 정도의 인재들을 지원금 몇 푼에 맘껏 사용할 수 있는 기회를 놓칠 순 없죠.","JPN":"とにかく、管理局カウンターアカデミーに選抜されるほどの人材を、\\nほんの少しの補助金で利用できるチャンスを逃すわけにはいきませんからね。","ENG":"Anyway, we can't just ignore the chance to utilize Administration Academy's young talents at the small cost of some pet food.","TWN":"總之，我們不能錯過用一點支援金，就隨意差遣管理局學院人才的機會。"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"다른 태스크포스 놈들이 채가기 전에 빨리 움직여야 할 것 같습니다.","JPN":"他のタスクフォースたちに横取りされる前に行動を起こすべきかと。","ENG":"We have to act fast before the other TASKFORCE companies get to them.","TWN":"我們得趕在其他特遣勢力的傢伙之前，盡快採取行動。"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"그러니 오늘 보고는 이쯤에서 끝내겠습니다.","JPN":"では、本日の報告はこれで終了いたします。","ENG":"Meaning, I'm going to end today's report here.","TWN":"所以今天的報告就到此為止。"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"알겠네.","JPN":"わかった。","ENG":"Very well.","TWN":"知道了。"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"노파심에서 하는 말이지만, 아무리 자원봉사라고 해도 청소년 근로기준은 꼭 지키도록 하게나.","JPN":"よくわかっているとは思うが、いくらボランティアだとは言え、\\n未成年の勤労基準は遵守するように。","ENG":"I'm just saying this out of concern, but make sure to follow youth employment laws when using them as volunteers.","TWN":"雖然這樣說有點多管閒事，但不管是什麼樣的志工，也一定要遵守青少年勞工基準啊。"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};